drop extension if exists "pg_net";


  create table "public"."brands" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "updated_at" timestamp with time zone,
    "name" text not null,
    "description" text,
    "logo_url" text,
    "slug" text not null
      );


alter table "public"."brands" enable row level security;


  create table "public"."chips" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "updated_at" timestamp with time zone,
    "name" text not null,
    "description" text,
    "brand_id_fk" bigint not null,
    "photo_url" text,
    "user_id_fk" uuid not null default auth.uid(),
    "slug" text not null
      );


alter table "public"."chips" enable row level security;


  create table "public"."profiles" (
    "id" uuid not null,
    "updated_at" timestamp with time zone,
    "username" text not null,
    "email" text not null,
    "avatar_url" text,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."profiles" enable row level security;


  create table "public"."reviews" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "updated_at" timestamp with time zone,
    "review" text not null,
    "photo_url" text,
    "rating" smallint not null,
    "user_id_fk" uuid not null,
    "chips_id_fk" bigint not null
      );


alter table "public"."reviews" enable row level security;

CREATE UNIQUE INDEX brands_name_key ON public.brands USING btree (name);

CREATE UNIQUE INDEX brands_pkey ON public.brands USING btree (id);

CREATE UNIQUE INDEX brands_slug_key ON public.brands USING btree (slug);

CREATE UNIQUE INDEX chips_pkey ON public.chips USING btree (id);

CREATE UNIQUE INDEX chips_slug_key ON public.chips USING btree (slug);

CREATE UNIQUE INDEX profiles_email_key ON public.profiles USING btree (email);

CREATE UNIQUE INDEX profiles_pkey ON public.profiles USING btree (id);

CREATE UNIQUE INDEX profiles_username_key ON public.profiles USING btree (username);

CREATE UNIQUE INDEX reviews_pkey ON public.reviews USING btree (id);

alter table "public"."brands" add constraint "brands_pkey" PRIMARY KEY using index "brands_pkey";

alter table "public"."chips" add constraint "chips_pkey" PRIMARY KEY using index "chips_pkey";

alter table "public"."profiles" add constraint "profiles_pkey" PRIMARY KEY using index "profiles_pkey";

alter table "public"."reviews" add constraint "reviews_pkey" PRIMARY KEY using index "reviews_pkey";

alter table "public"."brands" add constraint "brands_name_key" UNIQUE using index "brands_name_key";

alter table "public"."brands" add constraint "brands_slug_key" UNIQUE using index "brands_slug_key";

alter table "public"."chips" add constraint "chips_brand_id_fk_fkey" FOREIGN KEY (brand_id_fk) REFERENCES public.brands(id) not valid;

alter table "public"."chips" validate constraint "chips_brand_id_fk_fkey";

alter table "public"."chips" add constraint "chips_slug_key" UNIQUE using index "chips_slug_key";

alter table "public"."chips" add constraint "chips_user_id_fk_fkey" FOREIGN KEY (user_id_fk) REFERENCES public.profiles(id) not valid;

alter table "public"."chips" validate constraint "chips_user_id_fk_fkey";

alter table "public"."profiles" add constraint "profiles_email_key" UNIQUE using index "profiles_email_key";

alter table "public"."profiles" add constraint "profiles_id_fkey" FOREIGN KEY (id) REFERENCES auth.users(id) ON DELETE CASCADE not valid;

alter table "public"."profiles" validate constraint "profiles_id_fkey";

alter table "public"."profiles" add constraint "profiles_username_key" UNIQUE using index "profiles_username_key";

alter table "public"."profiles" add constraint "username_length" CHECK ((char_length(username) >= 3)) not valid;

alter table "public"."profiles" validate constraint "username_length";

alter table "public"."reviews" add constraint "reviews_chips_id_fk_fkey" FOREIGN KEY (chips_id_fk) REFERENCES public.chips(id) not valid;

alter table "public"."reviews" validate constraint "reviews_chips_id_fk_fkey";

alter table "public"."reviews" add constraint "reviews_user_id_fk_fkey" FOREIGN KEY (user_id_fk) REFERENCES public.profiles(id) not valid;

alter table "public"."reviews" validate constraint "reviews_user_id_fk_fkey";

set check_function_bodies = off;

create or replace view "public"."chips_with_stats" as  SELECT c.id,
    c.created_at,
    c.updated_at,
    c.name,
    c.description,
    c.brand_id_fk,
    c.photo_url,
    c.user_id_fk,
    c.slug,
    count(r.id) AS review_count,
    round(avg(r.rating), 1) AS average_rating
   FROM (public.chips c
     LEFT JOIN public.reviews r ON ((r.chips_id_fk = c.id)))
  GROUP BY c.id;


CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
begin
  insert into public.profiles (id, email, username, avatar_url)
  values (new.id, new.email, new.raw_user_meta_data->>'username', new.raw_user_meta_data->>'avatar_url');
  return new;
end;
$function$
;

