  create policy "Enable insert for authenticated users only"
  on "public"."brands"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Enable read access for all users"
  on "public"."brands"
  as permissive
  for select
  to public
using (true);



  create policy "Enable insert for authenticated users only"
  on "public"."chips"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Enable read access for all users"
  on "public"."chips"
  as permissive
  for select
  to public
using (true);



  create policy "Public profiles are viewable by everyone."
  on "public"."profiles"
  as permissive
  for select
  to public
using (true);



  create policy "Users can insert their own profile."
  on "public"."profiles"
  as permissive
  for insert
  to public
with check ((( SELECT auth.uid() AS uid) = id));



  create policy "Users can update own profile."
  on "public"."profiles"
  as permissive
  for update
  to public
using ((( SELECT auth.uid() AS uid) = id));



  create policy "Enable delete for users based on user_id"
  on "public"."reviews"
  as permissive
  for delete
  to public
using ((( SELECT auth.uid() AS uid) = user_id_fk));



  create policy "Enable insert for authenticated users only"
  on "public"."reviews"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Enable read access for all users"
  on "public"."reviews"
  as permissive
  for select
  to public
using (true);



  create policy "can update own review"
  on "public"."reviews"
  as permissive
  for update
  to authenticated
using ((auth.uid() = user_id_fk))
with check ((auth.uid() = user_id_fk));


CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();


